import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"IP Geolocation এবং User Management","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/ip-geolocation-and-user-management.md","filePath":"bn-BD/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"bn-BD/Other/ip-geolocation-and-user-management.md"};function u(g,e,h,m,b,f){return d(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-এবং-user-management" tabindex="-1">IP Geolocation এবং User Management <a class="header-anchor" href="#ip-geolocation-এবং-user-management" aria-label="Permalink to &quot;IP Geolocation এবং User Management&quot;">​</a></h1><p>IP geolocation uploader records, login devices এবং similar logs-এর IP addresses-কে approximate locations-এ রূপান্তর করে।</p><p>Configure করার পর admin panel upload এবং access origins আরও পরিষ্কারভাবে দেখাতে পারে। User Management suspicious IP addresses-এর upload access block বা restore করতেও সাহায্য করে।</p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>খুলুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>নতুন IP geolocation flow এক map service-এর ওপর নির্ভর না করে multiple sources support করে।</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Display language নির্বাচন করে, যেমন English, Simplified Chinese, Japanese, French ইত্যাদি।</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service-এর জন্য MaxMind account ID।</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key।</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key। Chinese addresses এবং mainland China IPs-এর জন্য useful।</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key। Multilingual IP geolocation support করে।</td></tr></tbody></table><p>শুধু প্রয়োজনীয় services পূরণ করুন। সব field configure করার দরকার নেই।</p><p>কোনো key না দিলে ImgBed built-in free sources try করে, তবে stability, language support এবং precision নিজের configured service-এর মতো ভালো নাও হতে পারে।</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>মূলত Chinese addresses দরকার হলে:</p><ol><li>IP geolocation language Simplified Chinese সেট করুন।</li><li>Tencent Map Key configure করুন।</li><li>Optional fallback হিসেবে MaxMind বা ipapi যোগ করুন।</li></ol><p>মূলত English বা multilingual addresses দরকার হলে:</p><ol><li>দরকারি language নির্বাচন করুন।</li><li>MaxMind Account ID এবং License Key configure করুন।</li><li>আরও ভালো multilingual results চাইলে ipapi Key যোগ করুন।</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind-এর দরকার:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>MaxMind dashboard থেকে account ID খুঁজুন এবং License Keys page থেকে License Key generate করুন।</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>Generate করার পর Account ID এবং License Key ImgBed-এ paste করে save করুন।</p><p>MaxMind free plan everyday use-এর জন্য যথেষ্ট, তবে request limits আছে। Quota exceed হলে ImgBed অন্য available sources try করবে।</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi APILayer API Key ব্যবহার করে।</p><p>ipapi console খুলে সেখানে দেখানো API Key copy করুন।</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>ImgBed-এর <code>ipapi Key</code> field-এ paste করে save করুন।</p><p>ipapi multilingual IP geolocation support করে এবং selected language-এ addresses দেখাতে চাইলে useful। Free plan-এ request limits আছে। Quota শেষ হলে ImgBed অন্য available sources try করবে।</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key Chinese addresses, বিশেষ করে mainland China IPs-এর জন্য useful।</p><p>Tencent Location Service-এ key তৈরি করার সময় enable করুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Creation-এর পর key <code>Tencent Map Key</code>-এ paste করে save করুন।</p><p>শুধু basic Chinese IP geolocation দরকার হলে Tencent Map Key দিয়ে শুরু করলেই হয়।</p><h2 id="user-management-এ-কী-দেখবেন" tabindex="-1">User Management-এ কী দেখবেন <a class="header-anchor" href="#user-management-এ-কী-দেখবেন" aria-label="Permalink to &quot;User Management-এ কী দেখবেন&quot;">​</a></h2><p>User Management admin panel-এর top থেকে পাওয়া যায়।</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management IP অনুযায়ী upload activity দেখায়:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>Uploader source IP।</td></tr><tr><td>Address</td><td>IP থেকে resolved approximate location।</td></tr><tr><td>Total upload size</td><td>এই IP থেকে uploaded total file size।</td></tr><tr><td>Upload count</td><td>এই IP থেকে uploads সংখ্যা।</td></tr><tr><td>Upload allowed</td><td>On মানে uploads allowed। Off মানে uploads blocked।</td></tr></tbody></table><p>সেই IP থেকে uploaded files-এর list খুলতে left arrow ক্লিক করুন।</p><p>File list file name, preview, file size, moderation result, file status এবং upload time দেখায়। Uploads suspicious লাগলে আগে IP expand করে files review করুন, তারপর further uploads block করবেন কি না সিদ্ধান্ত নিন।</p><p>IP suspicious হলে <code>Upload allowed</code> off করুন। Future uploads সেই IP থেকে block হবে।</p><h2 id="search-sort-এবং-advanced-filters" tabindex="-1">Search, Sort এবং Advanced Filters <a class="header-anchor" href="#search-sort-এবং-advanced-filters" aria-label="Permalink to &quot;Search, Sort এবং Advanced Filters&quot;">​</a></h2><p>User Management-এর top-এ IP source বা address দিয়ে search করুন।</p><p>Recent uploaders, high-frequency uploaders বা high-usage IPs খুঁজতে time, upload count বা total upload size দিয়ে sort করুন।</p><p>আরও গভীর তদন্তের জন্য advanced filters খুলুন।</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters support করে:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>Selected period-এ files upload করা IPs দেখায়।</td></tr><tr><td>Access status</td><td>Normal, blocked এবং similar states দিয়ে filter করে।</td></tr><tr><td>Allow/block list</td><td>Allowlist, blocklist বা unset দিয়ে filter করে।</td></tr><tr><td>File type</td><td>Images, videos, audio, documents, code বা other files upload করা IPs দেখায়।</td></tr><tr><td>File size</td><td>Uploaded file size range দিয়ে filter করে।</td></tr><tr><td>Age rating</td><td>Unset, General, R12+, R16+, R18 এবং similar ratings দিয়ে filter করে।</td></tr><tr><td>File status</td><td>Abnormal files investigate করতে current file status দিয়ে filter করে।</td></tr></tbody></table><p>Apply করতে <code>Apply Filters</code> ক্লিক করুন। সব data-তে ফিরতে <code>Reset</code> ব্যবহার করুন।</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>Mobile-এ User Management card layout-এ switch করে।</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>প্রতিটি card IP, address, total upload size, upload count এবং upload allowed switch দেখায়। Horizontal table scrolling ছাড়াই users manage করা যায়।</p><h2 id="location-ভুল-মনে-হলে" tabindex="-1">Location ভুল মনে হলে <a class="header-anchor" href="#location-ভুল-মনে-হলে" aria-label="Permalink to &quot;Location ভুল মনে হলে&quot;">​</a></h2><p>IP geolocation approximate। এটি precise street address নয়।</p><p>User proxy, data center, cloud server বা cross-border network-এর পেছনে থাকলে displayed location real location থেকে আলাদা হতে পারে।</p><p>এই feature rough origin বোঝা, abnormal uploads খোঁজা এবং blocking decisions-এ সহায়তার জন্য ব্যবহার করুন। Precise tracking হিসেবে ধরবেন না।</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address empty</td><td>IP এখনও resolve হয়নি, বা current source temporarily unavailable।</td></tr><tr><td>Address language ভুল</td><td>IP geolocation language এবং সেই language support করা source configured কি না check করুন।</td></tr><tr><td>Address data center দেখাচ্ছে</td><td>অনেক proxies, cloud servers এবং crawlers data center বা ISP addresses হিসেবে দেখা যায়।</td></tr><tr><td>Upload count high</td><td>IP ভালোভাবে review করুন এবং দরকার হলে uploads block করুন।</td></tr><tr><td>Total upload size বড়</td><td>Sort বা filter করুন, IP expand করে specific files inspect করুন।</td></tr><tr><td>Blocking-এর পর restore দরকার</td><td><code>Upload allowed</code> আবার on করুন।</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Settings-এ IP Geolocation খুলুন</span></span>
<span class="line"><span>-&gt; IP geolocation language নির্বাচন করুন</span></span>
<span class="line"><span>-&gt; দরকার অনুযায়ী MaxMind, Tencent Map বা ipapi credentials পূরণ করুন</span></span>
<span class="line"><span>-&gt; Settings save করুন</span></span>
<span class="line"><span>-&gt; User Management খুলুন</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size এবং upload count review করুন</span></span>
<span class="line"><span>-&gt; Abnormal IPs খুঁজতে search, sort বা advanced filters ব্যবহার করুন</span></span>
<span class="line"><span>-&gt; প্রয়োজন অনুযায়ী uploads allow বা block করুন</span></span></code></pre></div>`,64)])])}const I=l(c,[["render",u]]);export{v as __pageData,I as default};
